void clean_meta_value(meta * m) {
	char * read = m->value;
	char * stop = m->value + m->value_len;
	char * write = m->value;

	while (read < stop) {
		// Strip out redundant char_is_whitespace
		switch (*read) {
			case ' ':
			case '\t':
			case '\n':
			case '\r':
				*write = ' ';

				while ((read < stop - 1) && char_is_whitespace_or_line_ending(read[1])) {
					read++;
				}

				break;

			case '\\':
				if (char_is_whitespace_or_line_ending(read[1])) {
					*write = '\n';
					read++;

					while ((read < stop - 1) && char_is_whitespace_or_line_ending(read[1])) {
						read++;
					}
				} else {
					*write = *read;
				}

				break;

			default:
				*write = *read;
				break;
		}

		read++;
		write++;
	}

	write--;

	if (write >= m->value && *write == ' ') {
		*write = '\0';
	} else {
		write++;
	}

	m->value_len = write - m->value;
}


